// Generated by Copilot
export type PublicAssetRoot = 'Bitmaps' | 'Graphics' | 'icons' | 'images' | 'LayoutPhantoms' | 'PredefinedElements' | 'library';
export type PublicAssetKind = 'image' | 'vector' | 'audio' | 'model' | 'xml' | 'preset' | 'effect' | 'binary' | 'document';
export type PublicAssetSemanticUsage = 'overlay' | 'preset' | 'dental-library' | 'reference';

export interface PublicAssetSemanticProfile {
  usage: PublicAssetSemanticUsage;
  label: string;
  description: string;
  autoTags: string[];
  families: string[];
}

const KEYWORD_TAGS: Record<string, string[]> = {
  smilers: ['smilers', 'smile-design'],
  smile: ['smile-design'],
  smiledesign: ['smile-design'],
  implant: ['implant'],
  implantology: ['implant'],
  articulator: ['articulator', 'occlusion'],
  materials: ['materials'],
  material: ['materials'],
  guide: ['surgical-guide'],
  surgical: ['surgical-guide'],
  phantom: ['overlay'],
  layout: ['overlay', 'layout'],
  predefined: ['preset'],
  teeth: ['teeth-library'],
  tooth: ['teeth-library'],
  pontics: ['pontic'],
  prosthetic: ['prosthetic'],
  retention: ['retention'],
  nest: ['nesting'],
  nesting: ['nesting'],
  production: ['manufacturing'],
  bar: ['bar-design'],
  attachments: ['attachments'],
  attachment: ['attachments'],
  bolts: ['fasteners'],
  control: ['controls'],
  controls: ['controls'],
  visualizer: ['visualizer'],
  visualizers: ['visualizer'],
  gfx: ['graphics'],
  render: ['rendering'],
  effects: ['rendering'],
  arnett: ['cephalometry'],
  ceph: ['cephalometry'],
  airway: ['airway'],
  report: ['reporting'],
  docs: ['documentation'],
  tlantishare: ['sharing'],
  feature: ['feature-replica'],
  replicas: ['feature-replica'],
  replica: ['feature-replica'],
  waxup: ['waxup', 'smile-design'],
  denture: ['denture'],
  alignment: ['alignment', 'registration'],
  gum: ['denture', 'gingiva'],
  hollow: ['model-creator'],
  solid: ['model-creator'],
};

function normalizeToken(value: string) {
  return value
    .normalize('NFKD')
    .replace(/[^a-zA-Z0-9]+/g, ' ')
    .trim()
    .toLowerCase();
}

function tokenize(value: string) {
  return normalizeToken(value)
    .split(/\s+/)
    .filter(Boolean);
}

function uniq(values: string[]) {
  return Array.from(new Set(values));
}

export function derivePublicAssetSemanticProfile(input: {
  root: PublicAssetRoot;
  name: string;
  relativePath: string;
  kind: PublicAssetKind;
  extension: string;
}): PublicAssetSemanticProfile {
  const segments = input.relativePath.split('/').flatMap((segment) => tokenize(segment));
  const nameTokens = tokenize(input.name);
  const tokens = uniq([input.root.toLowerCase(), ...segments, ...nameTokens]);

  const families: string[] = [];
  const inferredTags = new Set<string>([input.root.toLowerCase(), input.kind]);

  for (const token of tokens) {
    const mapped = KEYWORD_TAGS[token];
    if (mapped) {
      mapped.forEach((tag) => inferredTags.add(tag));
      families.push(...mapped);
    }
  }

  let usage: PublicAssetSemanticUsage = 'reference';
  let label = 'Reference asset';
  let description = 'Useful as source, documentation or visual reference inside the app.';

  const isLayoutPhantom = input.root === 'LayoutPhantoms' || inferredTags.has('overlay');
  const isPredefined = input.root === 'PredefinedElements' || inferredTags.has('preset');
  const isTeethLibrary = input.root === 'library' && input.relativePath.toLowerCase().includes('/teeth/');
  const isFeatureReplica = input.root === 'library' && input.relativePath.toLowerCase().includes('/feature-replicas/');

  if (isFeatureReplica) {
    usage = 'dental-library';
    label = 'Feature replica CAD asset';
    description = 'Local reference mesh or workflow asset imported from feature replicas for CAD module parity.';
    inferredTags.add('dental-library');
    inferredTags.add('feature-replica');
  } else if (isTeethLibrary) {
    usage = 'dental-library';
    label = 'Dental library';
    description = 'Semantic dental library that should arm tooth presets, prosthetic selections or reference tooth sets.';
    inferredTags.add('dental-library');
    inferredTags.add('teeth-library');
  } else if (isLayoutPhantom) {
    usage = 'overlay';
    label = 'Overlay phantom';
    description = 'Ideal for CAD overlays, tracing guides and visual alignment phantoms.';
    inferredTags.add('overlay');
  } else if (isPredefined || input.kind === 'xml' || input.kind === 'preset') {
    usage = 'preset';
    label = 'Preset / predefined element';
    description = 'Useful as predefined setup, ceph preset, manufacturing preset or reusable workflow element.';
    inferredTags.add('preset');
  }

  return {
    usage,
    label,
    description,
    autoTags: uniq(Array.from(inferredTags).filter(Boolean)).sort(),
    families: uniq(families).sort(),
  };
}
